  1→import Ajv from 'ajv';
  2→import JSON5 from 'json5';
  3→import type { Diagnostic } from '@codemirror/lint';
  4→import type { EditorView } from '@codemirror/view';
  5→import { sduiScreenSchema, knownTypes, componentPropsSchemas } from './sduiSchema';
  6→
  7→const ajv = new Ajv({ allErrors: true, verbose: true, strict: false });
  8→const validate = ajv.compile(sduiScreenSchema);
  9→
 10→function didYouMean(input: string, candidates: string[]): string | null {
 11→  let best: string | null = null;
 12→  let bestDist = Infinity;
 13→
 14→  for (const candidate of candidates) {
 15→    const dist = levenshtein(input.toLowerCase(), candidate.toLowerCase());
 16→    if (dist < bestDist && dist <= Math.max(2, Math.floor(input.length / 2))) {
 17→      bestDist = dist;
 18→      best = candidate;
 19→    }
 20→  }
 21→  return best;
 22→}
 23→
 24→function levenshtein(a: string, b: string): number {
 25→  const m = a.length;
 26→  const n = b.length;
 27→  let prev = Array.from({ length: n + 1 }, (_, i) => i);
 28→
 29→  for (let i = 1; i <= m; i++) {
 30→    const curr = [i];
 31→    for (let j = 1; j <= n; j++) {
 32→      curr[j] = a[i - 1] === b[j - 1]
 33→        ? prev[j - 1]
 34→        : 1 + Math.min(prev[j], curr[j - 1], prev[j - 1]);
 35→    }
 36→    prev = curr;
 37→  }
 38→  return prev[n];
 39→}
 40→
 41→function findJsonPath(doc: string, path: string): { from: number; to: number } | null {
 42→  const segments = path.split('/').filter(Boolean);
 43→  let pos = 0;
 44→
 45→  for (const seg of segments) {
 46→    const isIndex = /^\d+$/.test(seg);
 47→
 48→    if (isIndex) {
 49→      const idx = parseInt(seg, 10);
 50→      let bracketDepth = 0;
 51→      let currentIdx = -1;
 52→      const arrStart = doc.indexOf('[', pos);
 53→      if (arrStart === -1) return null;
 54→      pos = arrStart + 1;
 55→
 56→      while (pos < doc.length && currentIdx < idx) {
 57→        const ch = doc[pos];
 58→        if (ch === '[' || ch === '{') bracketDepth++;
 59→        else if (ch === ']' || ch === '}') bracketDepth--;
 60→        else if (ch === ',' && bracketDepth === 0) currentIdx++;
 61→        else if (bracketDepth === 0 && /[^\s,]/.test(ch) && currentIdx < idx) {
 62→          if (currentIdx === -1) currentIdx = 0;
 63→          if (currentIdx === idx) break;
 64→        }
 65→        if (bracketDepth < 0) break;
 66→        pos++;
 67→      }
 68→
 69→      if (currentIdx < idx - 1) {
 70→        const lastBrace = doc.lastIndexOf('{', pos);
 71→        if (lastBrace >= arrStart) pos = lastBrace;
 72→      }
 73→    } else {
 74→      const escaped = seg.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
 75→      const keyPattern = new RegExp(`(?:"${escaped}"|${escaped})\\s*:`);
 76→      const match = keyPattern.exec(doc.slice(pos));
 77→      if (!match) return null;
 78→      pos += match.index;
 79→    }
 80→  }
 81→
 82→  let lineEnd = doc.indexOf('\n', pos);
 83→  if (lineEnd === -1) lineEnd = doc.length;
 84→
 85→  return { from: pos, to: Math.min(pos + 40, lineEnd) };
 86→}
 87→
 88→function humanizeMessage(error: Ajv.ErrorObject): string {
 89→  const { keyword, params, instancePath, message } = error;
 90→
 91→  if (keyword === 'enum' && instancePath.endsWith('/type')) {
 92→    const value = (error as any).data;
 93→    if (typeof value === 'string') {
 94→      const suggestion = didYouMean(value, [...knownTypes]);
 95→      const base = `Unknown component type "${value}"`;
 96→      return suggestion ? `${base} — did you mean "${suggestion}"?` : `${base}. Valid types: ${knownTypes.join(', ')}`;
 97→    }
 98→  }
 99→
100→  if (keyword === 'required') {
101→    const missing = (params as any).missingProperty;
102→    return `Missing required property "${missing}"`;
103→  }
104→
105→  if (keyword === 'additionalProperties') {
106→    const extra = (params as any).additionalProperty;
107→    return `Unknown property "${extra}"`;
108→  }
109→
110→  if (keyword === 'type') {
111→    const expected = (params as any).type;
112→    return `Expected ${expected}${message ? ` — ${message}` : ''}`;
113→  }
114→
115→  if (keyword === 'const') {
116→    return `Expected value: ${JSON.stringify((params as any).allowedValue)}`;
117→  }
118→
119→  return message || 'Schema validation error';
120→}
121→
122→function validateComponentProps(parsed: any, doc: string): Diagnostic[] {
123→  const diagnostics: Diagnostic[] = [];
124→
125→  const components: Array<{ component: any; path: string }> = [];
126→
127→  if (parsed.header) components.push({ component: parsed.header, path: '/header' });
128→  if (parsed.footer) components.push({ component: parsed.footer, path: '/footer' });
129→  if (Array.isArray(parsed.body)) {
130→    parsed.body.forEach((c: any, i: number) => components.push({ component: c, path: `/body/${i}` }));
131→  }
132→
133→  for (const { component, path } of components) {
134→    const type = component?.type;
135→    if (!type || typeof type !== 'string') continue;
136→
137→    if (!knownTypes.includes(type as any)) {
138→      const suggestion = didYouMean(type, [...knownTypes]);
139→      const loc = findJsonPath(doc, `${path}/type`);
140→      const msg = suggestion
141→        ? `Unknown component type "${type}" — did you mean "${suggestion}"?`
142→        : `Unknown component type "${type}". Valid: ${knownTypes.join(', ')}`;
143→      diagnostics.push({
144→        from: loc?.from ?? 0,
145→        to: loc?.to ?? 0,
146→        severity: 'warning',
147→        message: msg,
148→        source: 'sdui-schema',
149→      });
150→      continue;
151→    }
152→
153→    const propsSchema = componentPropsSchemas[type] as any;
154→    if (!propsSchema) continue;
155→
156→    const required: string[] = propsSchema.required || [];
157→    const props = component.props || {};
158→    const knownProps = Object.keys(propsSchema.properties || {});
159→
160→    for (const req of required) {
161→      if (props[req] === undefined || props[req] === null) {
162→        const loc = findJsonPath(doc, `${path}/props`);
163→        diagnostics.push({
164→          from: loc?.from ?? 0,
165→          to: loc?.to ?? 0,
166→          severity: 'error',
167→          message: `"${type}" requires property "${req}"`,
168→          source: 'sdui-schema',
169→        });
170→      }
171→    }
172→
173→    for (const propName of Object.keys(props)) {
174→      if (!knownProps.includes(propName)) {
175→        const suggestion = didYouMean(propName, knownProps);
176→        const loc = findJsonPath(doc, `${path}/props/${propName}`);
177→        const msg = suggestion
178→          ? `Unknown prop "${propName}" on "${type}" — did you mean "${suggestion}"?`
179→          : `Unknown prop "${propName}" on "${type}". Valid: ${knownProps.join(', ')}`;
180→        diagnostics.push({
181→          from: loc?.from ?? 0,
182→          to: loc?.to ?? 0,
183→          severity: 'warning',
184→          message: msg,
185→          source: 'sdui-schema',
186→        });
187→      }
188→    }
189→  }
190→
191→  return diagnostics;
192→}
193→
194→export function validateSduiJson(doc: string): Diagnostic[] {
195→  let parsed: any;
196→
197→  try {
198→    parsed = JSON.parse(doc);
199→  } catch {
200→    try {
201→      parsed = JSON5.parse(doc);
202→    } catch {
203→      return [];
204→    }
205→  }
206→
207→  if (typeof parsed !== 'object' || parsed === null || Array.isArray(parsed)) {
208→    return [{
209→      from: 0,
210→      to: Math.min(doc.length, 1),
211→      severity: 'error',
212→      message: 'SDUI screen must be a JSON object',
213→      source: 'sdui-schema',
214→    }];
215→  }
216→
217→  const diagnostics: Diagnostic[] = [];
218→
219→  validate(parsed);
220→  if (validate.errors) {
221→    for (const error of validate.errors) {
222→      if (error.keyword === 'if') continue;
223→
224→      const jsonPath = error.instancePath || '';
225→      const loc = findJsonPath(doc, jsonPath);
226→      const msg = humanizeMessage(error);
227→
228→      diagnostics.push({
229→        from: loc?.from ?? 0,
230→        to: loc?.to ?? 0,
231→        severity: error.keyword === 'required' || error.keyword === 'type' ? 'error' : 'warning',
232→        message: msg,
233→        source: 'sdui-schema',
234→      });
235→    }
236→  }
237→
238→  diagnostics.push(...validateComponentProps(parsed, doc));
239→
240→  const seen = new Set<string>();
241→  return diagnostics.filter(d => {
242→    const key = `${d.from}:${d.severity}:${d.message}`;
243→    if (seen.has(key)) return false;
244→    seen.add(key);
245→    return true;
246→  });
247→}
248→
249→export function sduiSchemaLinter(view: EditorView): Diagnostic[] {
250→  return validateSduiJson(view.state.doc.toString());
251→}
