 1→import React from 'react';
 2→import { View, Text as RNText } from 'react-native';
 3→import type { SDUIComponentProps } from '../models';
 4→
 5→interface FallbackProps {
 6→  props: SDUIComponentProps;
 7→  type: string;
 8→}
 9→
10→/**
11→ * Dev-only fallback for unregistered SDUI component types.
12→ * Uses RN primitives intentionally — DS components require ThemeProvider
13→ * which may not be available in all rendering contexts (tests, error boundaries).
14→ */
15→export default function FallbackComponent({ type, props }: FallbackProps) {
16→  return (
17→    <View
18→      style={{
19→        padding: 12,
20→        backgroundColor: '#FFF3CD',
21→        borderRadius: 8,
22→        marginBottom: 8,
23→      }}
24→    >
25→      <RNText style={{ fontWeight: 'bold', color: '#856404' }}>
26→        Unknown component: &quot;{type}&quot;
27→      </RNText>
28→      <RNText style={{ color: '#856404', fontSize: 12 }}>
29→        {JSON.stringify(props, null, 2)}
30→      </RNText>
31→    </View>
32→  );
33→}
